7	export class TypeDeclaration<InnerType extends TypeBuilder = TypeBuilder> implements BasicBuilder {
8	  private genericParameters: GenericParameter[] = []
9	  private docComment?: DocComment
10	
11	  constructor(
12	    public name: string,
13	    readonly type: InnerType,
14	  ) {}
15	
16	  addGenericParameter(param: GenericParameter): this {
17	    this.genericParameters.push(param)
18	    return this
19	  }
20	
21	  setName(name: string) {
22	    this.name = name
23	    return this
24	  }
25	
26	  setDocComment(docComment: DocComment): this {
27	    this.docComment = docComment
28	    return this
29	  }
30	
31	  write(writer: Writer): void {
32	    if (this.docComment) {
33	      writer.write(this.docComment)
34	    }
35	    writer.write('type ').write(this.name)
36	    if (this.genericParameters.length > 0) {
37	      writer.write('<').writeJoined(', ', this.genericParameters).write('>')
38	    }
39	    writer.write(' = ').write(this.type)
40	  }
41	}
42	
43	export function typeDeclaration<InnerType extends TypeBuilder = TypeBuilder>(name: string, type: InnerType) {
44	  return new TypeDeclaration(name, type)
