import type { DatamodelEnum } from '@prisma/dmmf'

/** Generates a const object + derived type for a single DMMF enum. */
export function generateEnumType(enumDef: DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  ${v.name}: '${v.name}'`).join(',\n')

  return [
    `export const ${enumDef.name} = {`,
    values,
    `} as const`,
    ``,
    `export type ${enumDef.name} = (typeof ${enumDef.name})[keyof typeof ${enumDef.name}]`,
  ].join('\n')
}

