import type { Field, Model } from '@prisma/dmmf'

import { resolveFieldType } from '../scalar-type-map'

/** Generates the main model interface containing all fields. */
export function generateModelInterface(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'unsupported')
    .map((f) => `  ${f.name}: ${resolveFieldType(f)}`)
    .join('\n')

  return [`export interface ${model.name} {`, fields, `}`].join('\n')
}

function isScalarOrEnum(field: Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

function isAutoGenerated(field: Field): boolean {
  return (field.isId && field.hasDefaultValue) || field.isReadOnly || field.isUpdatedAt === true
}

/** Generates the CreateInput type for a model. */
export function generateCreateInput(model: Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnum(f) && !isAutoGenerated(f))

  const props = fields
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue
      const marker = optional ? '?' : ''
      const baseType = resolveFieldType({ ...f, isRequired: true } as Field)
      const fullType = !f.isRequired ? `${baseType} | null` : baseType
      return `  ${f.name}${marker}: ${fullType}`
    })
    .join('\n')

  return [`export interface ${model.name}CreateInput {`, props, `}`].join('\n')
}

/** Generates the UpdateInput type for a model (all fields optional). */
export function generateUpdateInput(model: Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnum(f) && !isAutoGenerated(f))

  const props = fields
    .map((f) => {
      const baseType = resolveFieldType({ ...f, isRequired: true } as Field)
      const fullType = !f.isRequired ? `${baseType} | null` : baseType
      return `  ${f.name}?: ${fullType}`
    })
    .join('\n')

  return [`export interface ${model.name}UpdateInput {`, props, `}`].join('\n')
}

/** Generates the WhereUniqueInput type containing @id and @unique fields. */
export function generateWhereUniqueInput(model: Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnum(f) && (f.isId || f.isUnique))

  const props = fields
    .map((f) => {
      const baseType = resolveFieldType({ ...f, isRequired: true } as Field)
      return `  ${f.name}?: ${baseType}`
    })
    .join('\n')

  return [`export interface ${model.name}WhereUniqueInput {`, props, `}`].join('\n')
}

/** Generates the WhereInput type containing all scalar/enum fields for filtering. */
export function generateWhereInput(model: Model): string {
  const fields = model.fields.filter((f) => isScalarOrEnum(f))

  const props = fields
    .map((f) => {
      const baseType = resolveFieldType({ ...f, isRequired: true } as Field)
      return `  ${f.name}?: ${baseType}`
    })
    .join('\n')

  return [`export interface ${model.name}WhereInput {`, props, `}`].join('\n')
}

