import type { Model } from '@prisma/dmmf'

function uncapitalize(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

/** Generates a resource class file with CRUD methods for a single model. */
export function generateModelResource(model: Model): string {
  const name = model.name
  const slug = uncapitalize(name)

  return `import type {
  ${name},
  ${name}CreateInput,
  ${name}UpdateInput,
  ${name}WhereUniqueInput,
  ${name}WhereInput,
} from '../types'

export class ${name}Resource {
  #baseUrl: string
  #fetchFn: typeof fetch

  constructor(baseUrl: string, fetchFn: typeof fetch = fetch) {
    this.#baseUrl = baseUrl
    this.#fetchFn = fetchFn
  }

  async findMany(params?: { where?: ${name}WhereInput }): Promise<${name}[]> {
    let query = ''
    if (params?.where) {
      const entries = Object.entries(params.where).filter(([, v]) => v !== undefined)
      if (entries.length > 0) {
        query = '?' + entries.map(([k, v]) => \`\${encodeURIComponent(k)}=\${encodeURIComponent(String(v))}\`).join('&')
      }
    }
    const res = await this.#fetchFn(\`\${this.#baseUrl}/${slug}\${query}\`, { method: 'GET' })
    if (!res.ok) {
      throw new Error(\`GET /${slug} failed with status \${res.status}\`)
    }
    return res.json() as Promise<${name}[]>
  }

  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
    const entry = Object.entries(where).find(([, v]) => v !== undefined)
    if (!entry) {
      throw new Error('At least one unique field must be provided')
    }
    const res = await this.#fetchFn(\`\${this.#baseUrl}/${slug}/\${encodeURIComponent(String(entry[1]))}\`, { method: 'GET' })
    if (res.status === 404) {
      return null
    }
    if (!res.ok) {
      throw new Error(\`GET /${slug}/:id failed with status \${res.status}\`)
    }
    return res.json() as Promise<${name}>
  }

  async create(data: ${name}CreateInput): Promise<${name}> {
    const res = await this.#fetchFn(\`\${this.#baseUrl}/${slug}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) {
      throw new Error(\`POST /${slug} failed with status \${res.status}\`)
    }
    return res.json() as Promise<${name}>
  }

  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
    const entry = Object.entries(where).find(([, v]) => v !== undefined)
    if (!entry) {
      throw new Error('At least one unique field must be provided')
    }
    const res = await this.#fetchFn(\`\${this.#baseUrl}/${slug}/\${encodeURIComponent(String(entry[1]))}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) {
      throw new Error(\`PATCH /${slug}/:id failed with status \${res.status}\`)
    }
    return res.json() as Promise<${name}>
  }

  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
    const entry = Object.entries(where).find(([, v]) => v !== undefined)
    if (!entry) {
      throw new Error('At least one unique field must be provided')
    }
    const res = await this.#fetchFn(\`\${this.#baseUrl}/${slug}/\${encodeURIComponent(String(entry[1]))}\`, {
      method: 'DELETE',
    })
    if (!res.ok) {
      throw new Error(\`DELETE /${slug}/:id failed with status \${res.status}\`)
    }
    return res.json() as Promise<${name}>
  }
}
`
}

