import fs from 'node:fs/promises'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateClientClass } from './codegen/generate-client-class'
import { generateEnumType } from './codegen/generate-enum-type'
import { generateIndexFile } from './codegen/generate-index-file'
import {
  generateCreateInput,
  generateModelInterface,
  generateUpdateInput,
  generateWhereInput,
  generateWhereUniqueInput,
} from './codegen/generate-model-interface'
import { generateModelResource } from './codegen/generate-model-resource'

export interface GenerateRestClientOptions {
  dmmf: DMMF.Document
  outputDir: string
  baseUrl: string
}

export async function generateRestClient(options: GenerateRestClientOptions): Promise<void> {
  const { dmmf, outputDir } = options
  const { models, enums } = dmmf.datamodel

  await fs.mkdir(outputDir, { recursive: true })
  await fs.mkdir(path.join(outputDir, 'resources'), { recursive: true })

  // types.ts — enums + model interfaces + input types
  const typeSections: string[] = []

  if (enums.length > 0) {
    typeSections.push('// Enums')
    for (const enumDef of enums) {
      typeSections.push(generateEnumType(enumDef))
    }
    typeSections.push('')
  }

  typeSections.push('// Model interfaces')
  for (const model of models) {
    typeSections.push(generateModelInterface(model))
  }

  typeSections.push('')
  typeSections.push('// Input types')
  for (const model of models) {
    typeSections.push(generateCreateInput(model))
    typeSections.push(generateUpdateInput(model))
    typeSections.push(generateWhereUniqueInput(model))
    typeSections.push(generateWhereInput(model))
  }

  await fs.writeFile(path.join(outputDir, 'types.ts'), typeSections.join('\n\n') + '\n')

  // resources/{Model}Resource.ts
  for (const model of models) {
    const resourceContent = generateModelResource(model)
    await fs.writeFile(path.join(outputDir, 'resources', `${model.name}Resource.ts`), resourceContent)
  }

  // client.ts
  await fs.writeFile(path.join(outputDir, 'client.ts'), generateClientClass(models))

  // index.ts
  await fs.writeFile(path.join(outputDir, 'index.ts'), generateIndexFile(models))
}

