  for (const model of models) {
    typeSections.push(generateModelInterface(model))
  }

  typeSections.push('')
  typeSections.push('// Input types')
  for (const model of models) {
    typeSections.push(generateCreateInput(model))
    typeSections.push(generateUpdateInput(model))
    typeSections.push(generateWhereUniqueInput(model))
    typeSections.push(generateWhereInput(model))
  }

  await fs.writeFile(path.join(outputDir, 'types.ts'), typeSections.join('\n\n') + '\n')

  // resources/{Model}Resource.ts
  for (const model of models) {
    const resourceContent = generateModelResource(model)
    await fs.writeFile(path.join(outputDir, 'resources', `${model.name}Resource.ts`), resourceContent)
  }

  // client.ts
  await fs.writeFile(path.join(outputDir, 'client.ts'), generateClientClass(models))

  // index.ts
  await fs.writeFile(path.join(outputDir, 'index.ts'), generateIndexFile(models))
}

