import type { Field } from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { prismaScalarToTsType, resolveFieldType } from '../scalar-type-map'

describe('prismaScalarToTsType', () => {
  test('maps all Prisma scalars to TypeScript types', () => {
    expect(prismaScalarToTsType['String']).toBe('string')
    expect(prismaScalarToTsType['Int']).toBe('number')
    expect(prismaScalarToTsType['Float']).toBe('number')
    expect(prismaScalarToTsType['Boolean']).toBe('boolean')
    expect(prismaScalarToTsType['DateTime']).toBe('string')
    expect(prismaScalarToTsType['BigInt']).toBe('string')
    expect(prismaScalarToTsType['Decimal']).toBe('string')
    expect(prismaScalarToTsType['Json']).toBe('unknown')
    expect(prismaScalarToTsType['Bytes']).toBe('string')
  })
})

function makeField(overrides: Partial<Field>): Field {
  return {
    kind: 'scalar',
    name: 'test',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    type: 'String',
    hasDefaultValue: false,
    ...overrides,
  } as Field
}

describe('resolveFieldType', () => {
  test('resolves scalar fields', () => {
    expect(resolveFieldType(makeField({ type: 'String' }))).toBe('string')
    expect(resolveFieldType(makeField({ type: 'Int' }))).toBe('number')
    expect(resolveFieldType(makeField({ type: 'Boolean' }))).toBe('boolean')
  })

  test('resolves enum fields by name', () => {
    expect(resolveFieldType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('resolves object (relation) fields by model name', () => {
    expect(resolveFieldType(makeField({ kind: 'object', type: 'Post' }))).toBe('Post')
  })

  test('resolves list fields as arrays', () => {
    expect(resolveFieldType(makeField({ kind: 'object', type: 'Post', isList: true }))).toBe('Post[]')
  })

  test('resolves nullable fields as union with null', () => {
    expect(resolveFieldType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('list takes precedence over nullable', () => {
    expect(resolveFieldType(makeField({ type: 'String', isList: true, isRequired: false }))).toBe('string[]')
  })

  test('resolves unsupported fields as unknown', () => {
    expect(resolveFieldType(makeField({ kind: 'unsupported', type: 'Unsupported' }))).toBe('unknown')
  })

  test('resolves unknown scalar types as unknown', () => {
    expect(resolveFieldType(makeField({ type: 'UnknownType' }))).toBe('unknown')
  })
})

