import fs from 'node:fs/promises'
import os from 'node:os'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator'
import { afterEach, beforeEach, describe, expect, test } from 'vitest'

import { PrismaClientRestGenerator } from '../generator'
import { simpleDocument } from './fixtures/simple-schema'

describe('PrismaClientRestGenerator', () => {
  const generator = new PrismaClientRestGenerator()
  let outputDir: string

  beforeEach(async () => {
    outputDir = await fs.mkdtemp(path.join(os.tmpdir(), 'prisma-rest-gen-'))
  })

  afterEach(async () => {
    await fs.rm(outputDir, { recursive: true, force: true })
  })

  test('name is prisma-client-rest', () => {
    expect(generator.name).toBe('prisma-client-rest')
  })

  test('getManifest returns expected manifest', async () => {
    const manifest = await generator.getManifest({
      name: 'rest',
      output: { fromEnvVar: null, value: '/tmp/out' },
      provider: { fromEnvVar: null, value: 'prisma-client-rest' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/test/schema.prisma',
    })

    expect(manifest.prettyName).toBe('Prisma REST Client')
    expect(manifest.defaultOutput).toBe('/tmp/out')
    expect(manifest.requiresEngines).toEqual([])
  })

  test('generate produces all expected files', async () => {
    const options: GeneratorOptions = {
      generator: {
        name: 'rest',
        output: { fromEnvVar: null, value: outputDir },
        provider: { fromEnvVar: null, value: 'prisma-client-rest' },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: simpleDocument,
      datasources: [],
      datamodel: '',
      version: 'test-version',
    }

    await generator.generate(options)

    const files = await fs.readdir(outputDir)
    expect(files).toContain('index.ts')
    expect(files).toContain('types.ts')
    expect(files).toContain('client.ts')
    expect(files).toContain('resources')

    const resources = await fs.readdir(path.join(outputDir, 'resources'))
    expect(resources).toContain('UserResource.ts')
    expect(resources).toContain('PostResource.ts')
  })

  test('generated types.ts contains model interfaces and enums', async () => {
    const options: GeneratorOptions = {
      generator: {
        name: 'rest',
        output: { fromEnvVar: null, value: outputDir },
        provider: { fromEnvVar: null, value: 'prisma-client-rest' },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: simpleDocument,
      datasources: [],
      datamodel: '',
      version: 'test-version',
    }

    await generator.generate(options)

    const typesContent = await fs.readFile(path.join(outputDir, 'types.ts'), 'utf-8')

    // Enum
    expect(typesContent).toContain('export const Role = {')
    expect(typesContent).toContain('export type Role = ')

    // Model interfaces
    expect(typesContent).toContain('export interface User {')
    expect(typesContent).toContain('export interface Post {')

    // Input types
    expect(typesContent).toContain('export interface UserCreateInput {')
    expect(typesContent).toContain('export interface UserUpdateInput {')
    expect(typesContent).toContain('export interface UserWhereUniqueInput {')
    expect(typesContent).toContain('export interface UserWhereInput {')
    expect(typesContent).toContain('export interface PostCreateInput {')
  })

  test('generated client.ts contains RestClient class', async () => {
    const options: GeneratorOptions = {
      generator: {
        name: 'rest',
        output: { fromEnvVar: null, value: outputDir },
        provider: { fromEnvVar: null, value: 'prisma-client-rest' },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      },
      otherGenerators: [],
      schemaPath: '/test/schema.prisma',
      dmmf: simpleDocument,
      datasources: [],
      datamodel: '',
      version: 'test-version',
    }

    await generator.generate(options)

    const clientContent = await fs.readFile(path.join(outputDir, 'client.ts'), 'utf-8')
    expect(clientContent).toContain('export class RestClient {')
    expect(clientContent).toContain('readonly user: UserResource')
    expect(clientContent).toContain('readonly post: PostResource')
  })

  test('throws when output is missing', async () => {
    await expect(
      generator.getManifest({
        name: 'rest',
        output: null,
        provider: { fromEnvVar: null, value: 'prisma-client-rest' },
        config: {},
        binaryTargets: [],
        previewFeatures: [],
        sourceFilePath: '/test/schema.prisma',
      }),
    ).rejects.toThrow('output path is required')
  })
})
